const autumn = new Autumn({ secretKey: process.env.AUTUMN_SECRET_KEY });

const delay = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

export const generateWithBudget = async (customerId, maxTokens) => {
  const lockId = `completion_${randomUUID()}`;

  const checkPayload = {
    customerId,
    featureId: 'ai-tokens',
    requiredBalance: maxTokens,
    sendEvent: true,
    lock: {
      enabled: true,
      lockId,
      expiresAt: Date.now() + 60000,
    },
  };

  const checkResponse = autumn.customers?.check
    ? await autumn.customers.check(checkPayload)
    : await autumn.check(checkPayload);

  if (!checkResponse.allowed) {
    throw new Error('Insufficient ai-tokens balance');
  }

  let tokensUsed;
  try {
    await delay(100);
    tokensUsed = Math.floor(maxTokens * 0.75);
  } catch (error) {
    await autumn.balances.finalize({ lockId, action: 'release' });
    throw error;
  }

  await autumn.balances.finalize({
    lockId,
    action: 'confirm',
    overrideValue: tokensUsed,
  });

